def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        complexity_factor = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 7):
                penalty += (ratio ** (4 * k)) / (k ** 4 + 2 * k)
            for j in range(1, 5):
                decay *= (1 - 1 / (ratio + j + 3))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            elif item > capacity * 4:
                score *= 3
            else:
                score *= 2.5
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            partial_sum = 0.0
            for x in range(1, 10):
                sign = (-1) ** x
                partial_sum += sign * (ratio ** x) / (x + 3)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 4))
            score = abs(partial_sum) * decay * 15
            priorities[i] = score
        elif 2 < ratio <= 3:
            temp = 0.0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 7)
                else:
                    temp += (ratio ** p) / (p * 5)
            multiplier = 30 if ratio < 2.3 else 20 if ratio < 2.7 else 12
            score = abs(temp) * multiplier
            if ratio > 2.8:
                extra = 0.0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m + 5)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp = 0.0
            for p in range(1, 18):
                if p % 5 == 0:
                    temp -= (ratio ** p) / (p * 4)
                elif p % 3 == 0:
                    temp += (ratio ** p) / (p * 3)
                else:
                    temp -= (ratio ** p) / (p * 6)
            multiplier = 28 if ratio < 1.3 else 22 if ratio < 1.7 else 14
            score = abs(temp) * multiplier
            if ratio > 1.85:
                extra = 0.0
                for m in range(1, 9):
                    extra += (ratio ** m) / (m + 4)
                score += extra * 2.5
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0.0
            for p in range(1, 20):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 2)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 4)
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                else:
                    temp_score -= (ratio ** p) / (p * 7)
            if ratio < 0.15:
                multiplier = 35
            elif ratio < 0.35:
                multiplier = 28
            elif ratio < 0.55:
                multiplier = 18
            elif ratio < 0.75:
                multiplier = 12
            else:
                multiplier = 10
            score = abs(temp_score) * multiplier
            if ratio > 0.9:
                extra_penalties = 0.0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z / (bins[i] + 2))
            complexity_factor = np.log1p(capacity) * np.sqrt(item + 1)
            priorities[i] *= factor * complexity_factor
            if ratio > 2:
                penalty_factor = 1.0
                for w in range(1, 4):
                    penalty_factor += ((ratio - w) / (w + 1)) ** 2
                priorities[i] *= penalty_factor
        elif bins[i] <= 0:
            priorities[i] = np.inf
    return priorities
